def count_primes(N):
    if N < 2:
        return 0

    is_prime = [True] * (N + 1)
    is_prime[0] = is_prime[1] = False

    for i in range(2, int(N**0.5) + 1):
        if is_prime[i]:
            for j in range(i * i, N + 1, i):
                is_prime[j] = False

    return sum(is_prime)

# Minimal unit tests for critical behaviors
def test_count_primes():
    assert count_primes(10) == 4  # Primes: 2, 3, 5, 7
    assert count_primes(0) == 0    # No primes
    assert count_primes(1) == 0    # No primes
    assert count_primes(2) == 1    # Only prime is 2
    assert count_primes(20) == 8   # Primes: 2, 3, 5, 7, 11, 13, 17, 19

# Adversarial/edge-case tests
def test_edge_cases():
    assert count_primes(100) == 25  # Primes up to 100
    assert count_primes(50) == 15    # Primes up to 50
    assert count_primes(1000) == 168  # Primes up to 1000

test_count_primes()
test_edge_cases()
